// Flatten Outreach /sequences -> one row per sequence for export/analysis.
// Spreads ALL sequence attributes so we can see the real field names + values.
const out = [];
for (const item of $input.all()) {
  const body = item.json || {};
  const list = Array.isArray(body.data) ? body.data : (Array.isArray(body) ? body : [body]);
  for (const seq of list) {
    if (!seq || seq.id == null) continue;
    const a = seq.attributes || {};
    out.push({ json: Object.assign(
      { sequence_id: String(seq.id),
        _name: a.name || '',
        _tags: Array.isArray(a.tags) ? a.tags.join(' | ') : '' },
      a) });
  }
}
if (out.length === 0) {
  throw new Error('No sequences returned - check the Outreach OAuth2 credential and token scope read_sequences.');
}
return out;
